import argparse
import json
import os
from pathlib import Path

import numpy as np
import soundfile as sf
import torch
import torchaudio
from torch.utils.data import DataLoader, Dataset, Sampler
from transformers import AutoFeatureExtractor, logging as hf_logging

from model import build_model

hf_logging.set_verbosity_error()
os.environ.setdefault('TRANSFORMERS_VERBOSITY', 'error')
os.environ.setdefault('HF_HUB_DISABLE_PROGRESS_BARS', '1')


def find_test_root(data_path: str) -> Path:
    seeds = [data_path, os.environ.get('RAB_DATA_DIR'), '/data', '/rab_data', '/workspace', '.']
    seen, cands = set(), []
    for p in seeds:
        if not p:
            continue
        root = Path(p)
        try:
            root = root.resolve()
        except Exception:
            pass
        if not root.exists() or str(root) in seen:
            continue
        seen.add(str(root))
        cands.append(root)
        if root.is_dir():
            try:
                for child in root.rglob('*'):
                    if child.is_dir():
                        cands.append(child)
            except Exception:
                pass
    uniq, seen = [], set()
    for p in cands:
        try:
            p = p.resolve()
        except Exception:
            pass
        s = str(p)
        if s not in seen:
            seen.add(s)
            uniq.append(p)
    for p in uniq:
        if (p / 'test.txt').is_file() and (p / 'flac').is_dir():
            return p
    raise FileNotFoundError(f'Could not locate test root under {data_path}')


def load_audio(path: Path) -> np.ndarray:
    try:
        wav, sr = sf.read(str(path), always_2d=False)
        if getattr(wav, 'ndim', 1) > 1:
            wav = wav.mean(axis=1)
        wav = wav.astype(np.float32)
    except Exception:
        wav, sr = torchaudio.load(str(path))
        if wav.dim() == 2 and wav.size(0) > 1:
            wav = wav.mean(dim=0, keepdim=True)
        wav = wav.squeeze(0).cpu().numpy().astype(np.float32)
    if sr != 16000:
        raise ValueError(f'Expected 16k audio, got {sr} for {path}')
    return wav


def get_num_frames(path: Path) -> int:
    try:
        return int(sf.info(str(path)).frames)
    except Exception:
        wav, _ = torchaudio.load(str(path))
        return int(wav.shape[-1])


class TestDataset(Dataset):
    def __init__(self, data_path: str):
        self.root = find_test_root(data_path)
        self.flac_dir = self.root / 'flac'
        with open(self.root / 'test.txt') as f:
            self.utt_ids = [x.strip() for x in f if x.strip()]
        self.paths = [self.flac_dir / f'{u}.flac' for u in self.utt_ids]
        self.lengths = [get_num_frames(p) for p in self.paths]

    def __len__(self):
        return len(self.utt_ids)

    def __getitem__(self, idx):
        return {'input_values': load_audio(self.paths[idx]), 'index': idx}


class SortedBatchSampler(Sampler):
    def __init__(self, lengths, batch_size: int):
        self.batch_size = batch_size
        self.indices = np.argsort(np.asarray(lengths)).tolist()

    def __iter__(self):
        batch = []
        for idx in self.indices:
            batch.append(idx)
            if len(batch) == self.batch_size:
                yield batch
                batch = []
        if batch:
            yield batch

    def __len__(self):
        return (len(self.indices) + self.batch_size - 1) // self.batch_size


class Collator:
    def __init__(self, feature_extractor):
        self.feature_extractor = feature_extractor

    def __call__(self, batch):
        wavs = [b['input_values'] for b in batch]
        enc = self.feature_extractor(
            wavs,
            sampling_rate=16000,
            return_tensors='pt',
            padding=True,
            return_attention_mask=True,
        )
        x = enc['input_values']
        m = enc['attention_mask'] if 'attention_mask' in enc else torch.ones_like(x, dtype=torch.long)
        idx = torch.tensor([b['index'] for b in batch], dtype=torch.long)
        return {'input_values': x, 'attention_mask': m, 'index': idx}


def extract_state_dict(ckpt):
    if not isinstance(ckpt, dict):
        return ckpt
    for k in ['model_state_dict', 'state_dict', 'model_state']:
        if k in ckpt and isinstance(ckpt[k], dict):
            return ckpt[k]
    tensor_items = {k: v for k, v in ckpt.items() if torch.is_tensor(v)}
    if tensor_items:
        return tensor_items
    raise ValueError('Could not extract state_dict from checkpoint')


def infer_encoder_name(ckpt):
    if isinstance(ckpt, dict):
        for key in ['model_config', 'model_kwargs']:
            val = ckpt.get(key)
            if isinstance(val, dict) and val.get('encoder_name'):
                return val['encoder_name']
        if ckpt.get('encoder_name'):
            return ckpt['encoder_name']
    return 'facebook/wav2vec2-xls-r-300m'


def infer_model_config(ckpt, state):
    cfg = {
        'encoder_name': infer_encoder_name(ckpt),
        'pooling': 'attentive',
        'proj_dim': 256,
        'dropout': 0.2,
        'unfreeze_last_n_layers': 0,
        'use_layer_weights': 'layer_weights' in state,
    }
    for key in ['model_config', 'model_kwargs']:
        val = ckpt.get(key) if isinstance(ckpt, dict) else None
        if isinstance(val, dict):
            cfg.update({k: v for k, v in val.items() if k in cfg})
    if 'head.0.weight' in state:
        cfg['proj_dim'] = int(state['head.0.weight'].shape[0])
    return cfg


def load_feature_extractor(encoder_name: str):
    local_dir = Path('artifacts/feature_extractor')
    if local_dir.exists():
        try:
            return AutoFeatureExtractor.from_pretrained(str(local_dir), local_files_only=True)
        except Exception:
            pass
    return AutoFeatureExtractor.from_pretrained(encoder_name, local_files_only=True)


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--data_path', required=True)
    ap.add_argument('--checkpoint', required=True)
    ap.add_argument('--output', required=True)
    ap.add_argument('--batch_size', type=int, default=64)
    args = ap.parse_args()

    device = 'cuda' if torch.cuda.is_available() else 'cpu'
    ckpt = torch.load(args.checkpoint, map_location='cpu')
    state = extract_state_dict(ckpt)
    cfg = infer_model_config(ckpt, state)
    model = build_model(cfg)
    model.load_state_dict(state, strict=False)
    model.to(device).eval()

    feature_extractor = load_feature_extractor(cfg['encoder_name'])
    ds = TestDataset(args.data_path)
    dl = DataLoader(
        ds,
        batch_sampler=SortedBatchSampler(ds.lengths, args.batch_size),
        num_workers=0,
        collate_fn=Collator(feature_extractor),
        pin_memory=(device == 'cuda'),
    )

    preds = np.zeros(len(ds), dtype=np.float32)
    amp = device == 'cuda'
    with torch.no_grad():
        for batch in dl:
            x = batch['input_values'].to(device, non_blocking=True)
            m = batch['attention_mask'].to(device, non_blocking=True)
            with torch.amp.autocast('cuda', dtype=torch.bfloat16, enabled=amp):
                y = model(x, m).float().cpu().numpy()
            preds[batch['index'].numpy()] = y

    out = Path(args.output)
    out.parent.mkdir(parents=True, exist_ok=True)
    with open(out, 'w') as f:
        json.dump({'predictions': [float(x) for x in preds.tolist()]}, f)


if __name__ == '__main__':
    main()
